%[text] # UWCC Structural Analysis and Reinforcement Design
%[text] Heerod Sahraei
% bismillahirahmanirahim
clear;
close all;
clc;
%%
%[text] ### 1. Physical Constants and Material Properties
%[text] These are constants throughout all analysis and designs for a given canoe. For the data below, receive relevant info from Hull Design team.
%[text] #### Input Coordinate Data (.csv)
% Set up the Import Options and import the data %[task:43b8]
opts = delimitedTextImportOptions("NumVariables", 4);

% Specify range and delimiter
opts.DataLines = [2, Inf];
opts.Delimiter = ",";

% Specify column names and types
opts.VariableNames = ["LongitudalPosition", "Offset", "Height", "Side"];
opts.VariableTypes = ["double", "double", "double", "categorical"];

% Specify file level properties
opts.ExtraColumnsRule = "ignore";
opts.EmptyLineRule = "read";

% Specify variable properties
opts = setvaropts(opts, "Side", "EmptyFieldRule", "auto");

% Import the data
HullCoordinates = readtable("C:\Users\heero\Documents\Local Repositories\UWCC Structural Analysis\HullCoordinates.csv", opts);

% Clear temporary variables
clear opts %[task:43b8]
xCoordinates = HullCoordinates.LongitudalPosition;
xUnique =  unique(xCoordinates);
canoeLength = abs(max(xCoordinates)) + abs(min(xCoordinates));
%[text] For the numbers below, receive from Mix Design team. Tensile strength can be pulled from split tensile test results, or set to 0 for more conservative design.
%[text] #### Input Structural Density of Concrete Mix (lbf/ft3)
 structuralDensity = 68.5 / 1728; % stores results in lbf/in3 %[control:editfield:77f0]{"position":[22,26]}
%[text] #### Input Concrete Compressive Strength (psi)
 compressiveStr = 2000; %[control:editfield:149e]{"position":[19,23]}
%[text] #### Input Concrete Tensile Strength (psi)
 tensileStr = 290; %[control:editfield:4eda]{"position":[15,18]}
%[text] For selecting the load and loss factors below, consider ASCE 7 standard structural LRFD and other citable sources.
%[text] #### Select Live Load Factor
 LIVE_FACTOR = 1.1; %[control:editfield:85a5]{"position":[16,19]}
%[text] #### Select Dead Load Factor
 DEAD_FACTOR = 1.5; %[control:editfield:683b]{"position":[16,19]}
%[text] #### Select Post-Tensioned Cable Strength Loss Factor
 CABLE_LOSS = 0.7; %[control:editfield:3b8d]{"position":[15,18]}
%[text] #### Select Concrete Compressive Strength Loss Factor
 CONCRETE_LOSS = 0.9 ; % ACI 318: 0.75 factor for lightweight concrete %[control:editfield:68b2]{"position":[18,21]}
%%
%[text] ### 2. Paddler Properties and Race Stand Positions
%[text] #### Select Male Paddler Weight (lbf)
 male = -200 * LIVE_FACTOR; %[control:editfield:979a]{"position":[10,13]}
%[text] #### Select Female Paddler Weight (lbf)
female = -160 * LIVE_FACTOR;  %[control:editfield:6f60]{"position":[11,14]}
%[text] #### Input Race Load Combinations
if ~exist("LoadCases", "var") 
    LoadCases = struct; 
end


%% Load Cases Input here: first row x-positions, second row forces
%  Negative is downwards or towards the stern, positive upwards or towards
%  the bow.
LoadCases.RaceStands.PointLoads   = [0; 0];
LoadCases.RaceStands.NotFloating  = true;
LoadCases.SelfWeight.PointLoads   = [0; 0];
LoadCases.MaleTandem.PointLoads   = [-90 90; male male];
LoadCases.FemaleTandem.PointLoads = [-90 90; female female];
LoadCases.Person4.PointLoads      = [-66 -36 36 66; male female female male];
LoadCases.Person3.PointLoads      = [-54 0 54; male female male];

caseNames = fieldnames(LoadCases);
%[text] #### Select Number of Race Stands
%[text] Don't go crazy with this... the solver isn't exactly perfect 
nStands =2; %[control:slider:4be4]{"position":[10,11]}
%[text] #### Select Race Stands Spacing (in)
standSeperation = 144; %[control:editfield:535a]{"position":[19,22]}
if (nStands-1) * standSeperation > canoeLength
    throw(MException('MyComponent:inputError', ...
        'Stands span longer than length of canoe'));
end

standPositions = zeros(1, nStands);
if mod(nStands, 2) == 1
    for i = 1:nStands
        middle_stand_num = (nStands - 1)/2 + 1;
        standPositions(i) = (i - middle_stand_num) * standSeperation;
    end
else
    for i = 1:nStands
        standPositions(i) = (i - (nStands)/2) * standSeperation - standSeperation/2;
    end
end
%%
%[text] ### 3. Force Analysis
%[text] #### Select Interpolation Rate for All Following Calculations
INTERPOLATION_RATE = 1000; %[control:editfield:0e83]{"position":[22,26]}
%[text] #### Estimate Avg. Draft During Load Cases (in)
draftGuess = 10; % draft is totalheight - freeboard %[control:slider:3819]{"position":[14,16]}
%[text] #### Select Minimum Freeboard for All Cases (in)
minFreeboard = 6; %[control:editfield:1b51]{"position":[16,17]}
%[text] #### Calculate Cross Section Information
csas       = zeros(numel(xUnique),1);
moInertias = zeros(numel(xUnique),1);
centroids  = zeros(numel(xUnique),1);
internalShapes = createArray(numel(xUnique),1,'polyshape');

ymin_all = 0; % variables will be used later for submerged area;
ymax_all = 0;
zmin_all = 0;
zmax_all = 0;

for i = 1:numel(xUnique)
    iX = xUnique(i);
    [innerCoords, outerCoords] = crosssectioncoords(iX,HullCoordinates);

    ymin_all = min(ymin_all,min(outerCoords(:,1)));
    ymax_all = max(ymax_all,max(outerCoords(:,1)));
    zmin_all = min(zmin_all,min(outerCoords(:,2)));
    zmax_all = max(zmin_all,max(outerCoords(:,2)));

    [csas(i), centroids(i)] = csa(innerCoords, outerCoords);
    moInertias(i) = moinertia(innerCoords, outerCoords);
    if isnan(moInertias(i))
        moInertias(i) = min(moInertias);
    end
    warning('off', 'all'); %polyshape will complain abt not "well-defined" shapes, IDC bitch!
    internalShapes(i) = internalshape(outerCoords);
    warning('on', 'all');
end
%[text] #### Interpolate Data
xInterp = linspace(min(xUnique),max(xUnique),INTERPOLATION_RATE);

csasInterp = interp1(xUnique,csas,xInterp,"linear");
moInertiasInterp = interp1(xUnique,moInertias,xInterp,"linear");
centroidsInterp = interp1(xUnique,centroids,xInterp,"linear");
%[text] #### Calculate Self-Weight
selfWeightInterp = -csasInterp .* (structuralDensity * DEAD_FACTOR);
%[text] #### Calculate Race Stand Reactions
% spanreactions implements stiffness method. taught in CEE 378
E = sqrt(compressiveStr * CONCRETE_LOSS) * 57000;
reactions = spanreactions(xInterp,selfWeightInterp,standPositions,moInertiasInterp,E);

LoadCases.RaceStands.PointLoads = [standPositions; reactions];
%%
%[text] ### 4. Buoyancy Solver
runSolver = true; % Run Solver %[control:checkbox:04ec]{"position":[13,17]}
if runSolver %[output:group:3cebcd74]
    run("SolveBuoyancy.m"); %[output:69b2a7ce]
    close
end %[output:group:3cebcd74]
% DEBUG: below takes forever to run dont try to run this repeatedly
% visualization of optimization
% [freeboard, angle] = meshgrid(0:0.1:17,-.01:.001:.01);
% for i = 1:size(freeboard,1)
%     for j = 1:size(freeboard,2)
%         z(i,j) = objective([freeboard(i,j), angle(i,j)]);
%     end
% end
% surf(freeboard, angle, z);
%%
%[text] ### 5. Shear, Moment, and Internal Stresses
%[text] #### Calculate Shear and Moment for all Cases + Race Stands
for i = 1:numel(caseNames)
    thisCase = LoadCases.(caseNames{i});
    buoyancyInterp = thisCase.BuoyantDistribution;
    [V, M] = shearmoment(xInterp,(buoyancyInterp + selfWeightInterp),...
        thisCase.PointLoads);
    LoadCases.(caseNames{i}).ShearDistribution = V;
    LoadCases.(caseNames{i}).MomentDistribution = M;
end
%[text] #### Calculate Maximums and Locations of Maximums
% use distributions from above
Mmax = zeros(numel(caseNames),2);
Mmin = zeros(numel(caseNames),1);
Vmax = zeros(numel(caseNames),1);
Vmin = zeros(numel(caseNames),1);
sKeelMax = zeros(numel(caseNames),1);
sKeelMin = zeros(numel(caseNames),1);
sGunnwaleMax = zeros(numel(caseNames),1);
sGunnwaleMin = zeros(numel(caseNames),1);
for i = 1:numel(caseNames)
    M = LoadCases.(caseNames{i}).MomentDistribution;
    V = LoadCases.(caseNames{i}).ShearDistribution;
    [Mmax(i,2), Mmax(i,1)] = max(M); 
    [Mmin(i,2), Mmin(i,1)] = min(M);
    [Vmax(i,2), Vmax(i,1)] = max(V);
    [Vmin(i,2), Vmin(i,1)] = min(V);
end

for i = 1:numel(caseNames)
    sKeelMax(i) = Mmax(i,2)*centroidsInterp(Mmax(i,1)) / moInertiasInterp(Mmax(i,1)); % keel stress from pos moment
    sKeelMin(i) = Mmin(i,2)*centroidsInterp(Mmin(i,1)) / moInertiasInterp(Mmin(i,1)); % keel stress from neg moment
    % gun. stress from pos moment
    sGunnwaleMax(i) = Mmax(i,2)*(centroidsInterp(Mmin(i,1)) - zmax_all) / moInertiasInterp(Mmax(i,1)); 
    % gun. stress from negative moment
    sGunnwaleMin(i) = Mmin(i,2)*(centroidsInterp(Mmin(i,1)) - zmax_all) / moInertiasInterp(Mmin(i,1));
end

maximums = table(caseNames,Mmax,Mmin,Vmax,Vmin,sGunnwaleMin,sGunnwaleMax,sKeelMin,sKeelMax) %[output:4cd2aeb1]

%%
%[text] ### 6. Cable Design
%[text] #### Select Cable Spacing (in)
cableSpacing = 3; %[control:slider:33a0]{"position":[16,17]}
%[text] #### Select Number of Cables
nCables = 8; %[control:slider:6e00]{"position":[11,12]}

critSections = maximums{:,"Mmin"};
criticalSection = round(mean(critSections(:,1)));
maxEccentricity = zmax_all - 1 - cableSpacing * (nCables/4-0.5) - centroidsInterp(criticalSection);
eccentricity = [-1 maxEccentricity];
%[text] #### Input Maximum Cable Force (lbf)
maxCableForce = 800; %[control:editfield:7a40]{"position":[17,20]}
maxForce = maxCableForce * nCables * CABLE_LOSS;
%[text] #### Display Cable Force Envelope
eInterp = eccentricity(1):.01:eccentricity(2);
% Max Cable force envelope
close;
hold on; %[output:59b3874e]

constraintsDim = [0 0 maxEccentricity maxForce];
plot(NaN,NaN,'s','Color','yellow','DisplayName','Cable Material Constraints'); %[output:59b3874e]
% ^ weird bullshit u gotta do to make an extra legend line show up
rectangle('Position',constraintsDim,'EdgeColor', 'yellow'); %[output:59b3874e]

legend('Location','best'); %[output:59b3874e]

xlim([-1 maxEccentricity]); %[output:59b3874e]

xlabel("Eccentricity (e) of cable centroid (in.)"); %[output:59b3874e]
ylabel("Total applied cable force (F) (lbf.)"); %[output:59b3874e]
%%--- Re arrange critical equation as force as function of eccentricity and allowable stresses

F_limit = @(sDemand,sAllow,A,c,e,I) (sDemand - sAllow)/(1/A + c*e/I);

%%--- Keel Envelopes

% Find most vulnerable keel 

%find most compressed keel part due to both pos and negative moments
[compressedKeelatMmax, idx_ckmax] = min(sKeelMax);
[compressedKeelatMmin, idx_ckmin] = min(sKeelMin);
if compressedKeelatMmin < compressedKeelatMmax
    idx_Comp = Mmin(idx_ckmin,1); %x-index for csa,moi,centroid etc.
    sCompK   = compressedKeelatMmin;
else
    idx_Comp = Mmax(idx_ckmax,1);
    sCompK   = compressedKeelatMmax;
end

% most tensioned part
[tensionKeelatMmax, idx_tkmax] = max(sKeelMax);
[tensionKeelatMmin, idx_tkmin] = max(sKeelMin);
if tensionKeelatMmax > tensionKeelatMmin
    idx_Tens = Mmax(idx_tkmax,1);
    sTensionK   = tensionKeelatMmax;
else
    idx_Tens = Mmax(idx_tkmin,1);
    sTensionK = tensionKeelatMmin;
end
% Find relevant properties of critical section (c is positive for keel)
cCompK        = centroidsInterp(idx_Comp);
cTensK        = centroidsInterp(idx_Tens);
csaCompK      = csasInterp(idx_Comp);
csaTensK      = csasInterp(idx_Tens);
moiCompK      = moInertiasInterp(idx_Comp);
moiTensK      = moInertiasInterp(idx_Tens);

% Allowable force as function of eccentricity
% Design for Tensile of 0 !!! ALWAYS

F_compKeel = @(e) F_limit(sCompK,-compressiveStr*CONCRETE_LOSS,csaCompK,cCompK,e,moiCompK);
F_tensKeel = @(e) F_limit(sTensionK,0,csaTensK,cTensK,e,moiTensK);

%%--- Gunnwale Envelopes

% Find most vulnerable gunnwale 

% most compressed
[compressedGunatMmax, idx_cgmax] = min(sGunnwaleMax);
[compressedGunatMmin, idx_cgmin] = min(sGunnwaleMin);

if compressedGunatMmin < compressedGunatMmax
    idx_Comp = Mmin(idx_cgmin,1);
    sCompG = compressedGunatMmin;
else
    idx_Comp = Mmax(idx_cgmax,1);
    sCompG   = compressedGunatMmax;
end

% most tensioned
[tensionGunatMmax, idx_tgmax] = max(sGunnwaleMax);
[tensionGunatMmin, idx_tgmin] = max(sGunnwaleMin);

if tensionGunatMmin > tensionGunatMmax
    idx_Tens = Mmin(idx_tgmin,1);
    sTensG = tensionGunatMmin;
else
    idx_Tens = Mmax(idx_tgmax,1);
    sTensG = tensionGunatMmax;
end

% find relevant cross section properties.

moiTensG = moInertiasInterp(idx_Tens);
moiCompG = moInertiasInterp(idx_Comp);
csaTensG = csasInterp(idx_Tens);
csaCompG = csasInterp(idx_Comp);

% Find lever arm (c is negative for gunnwale)
cCompG        = zmax_all - centroidsInterp(idx_Comp);
cTensG        = zmax_all - centroidsInterp(idx_Tens);

% allowable force as function of eccentricity
% allowable tensile is 0 as always
F_compGun = @(e) F_limit(sCompG,-compressiveStr*CONCRETE_LOSS,csaCompG,cCompG,e,moiCompG);
F_tensGun = @(e) F_limit(sTensG,0,csaTensG,cTensG,e,moiTensG);

ylim([-100 F_compGun(0)]); %[output:59b3874e]

plot(eInterp,arrayfun(F_compKeel,eInterp),"Color","red","DisplayName",'Crushing at Keel'); %[output:59b3874e]
plot(eInterp,arrayfun(F_tensKeel,eInterp),"Color","green","DisplayName",'Cracking at Keel'); %[output:59b3874e]
plot(eInterp,arrayfun(F_compGun,eInterp),"Color","#ee6600","DisplayName",'Crushing at Gunnwale'); %[output:59b3874e]
plot(eInterp,arrayfun(F_tensGun,eInterp),"Color","#00ee66","DisplayName",'Cracking at Gunnwale'); %[output:59b3874e]
%[text] #### Select Cable Force (lbf)
force = 570* nCables * CABLE_LOSS; %[control:slider:6f45]{"position":[9,12]}
%[text] #### Select Cable Eccentricity (in.)
eccentricity =4; %[control:slider:06da]{"position":[15,16]}
%%
%[text] ### 7. Punching Shear (per ACI 318 22.6.5.2)
%[text] #### Input Hull Thickness (in.)
hullThickness = 0.5; %[control:editfield:97d8]{"position":[17,20]}
%[text] #### Input Reinforcement Depth (in.)
reinforcementDepth = 0.25; %[control:slider:5c66]{"position":[22,26]}
%[text] ![](text:image:8710)
% Constants
alphaS = 40; % interior column
lambda = 0.75; % lightweight concrete strength reduction factor
lambdaS = min(1,sqrt(2/(1+hullThickness/10))); % ACI 318 22.5.5.1.3
L      = 3; % knee width
beta   = 1; % knee width/length ratio
effectivePerimeter = 4*(L+reinforcementDepth);
shearDemand = max(max(Vmax(:,2)),male); % highest shear is either paddler-weight or internal shear to be conservative
A = effectivePerimeter * hullThickness;
shearDemand = shearDemand / A;

shearCapacity = min([4,(2+4/beta),(2+alphaS*reinforcementDepth/effectivePerimeter)]);
shearCapacity = shearCapacity *lambdaS*lambda*sqrt(compressiveStr);
%%
%[text] 
%[text] ### 8. DCR and Final Values
%[text] $\\sigma^{\\pm}\_{\\mathrm{max}}=\\frac{M^{\\pm}\_{\\mathrm{max}}\\cdot c}{I\_{z}} - \\frac{F}{A\_{cs}} + \\frac{(F\\cdot e)\\cdot c}{I\_{z}} + \\mathrm{AI}${"altText":"Critical Equation"}
%[text] *Critical Stress Equation*
% our beloved equation - the AI
theequation = @(bendingStress,c,e,I,F,A) bendingStress - F/A - (F*c)*e/I;
%[text] #### Demand to Capacity Ratios
compDemand = min(theequation(sCompG,zmax_all - cCompG,eccentricity,moiCompG,force,csaCompG),...
                     theequation(sCompK,cCompK,eccentricity,moiCompK,force,csaCompK));
tensDemand = max(theequation(sTensG,zmax_all - cTensG,eccentricity,moiTensG,force,csaTensG),...
                     theequation(sTensionK,cTensK,eccentricity,moiTensK,force,csaTensK));
compDemand = abs(min(0,compDemand)); % clamp value
tensDemand = abs(max(tensDemand,0)); % clamp value
out1 = sprintf("Compressive Demand (psi): %g Capacity (psi): %g Ratio (%%): %g\n", compDemand, compressiveStr, compDemand/compressiveStr*100);
out2 = sprintf("Tensile Demand (psi): %g Capacity (psi): %g Ratio (%%): %g\n", tensDemand, tensileStr, tensDemand/tensileStr*100);
out3 = sprintf("Punching Shear Demand (psi): %g Capacity (psi): %g Ratio (%%): %g\n", shearDemand, shearCapacity, shearDemand/shearCapacity*100);
fprintf("%s%s%s", out1, out2, out3); %[output:7627442b]

